findings.suggestion:
Add a validated factory function that enforces invariants:

export function createDoNotDisturbConfig(params: Partial<DoNotDisturbConfig> = {}): DoNotDisturbConfig {
  const config = { ...createDefaultConfig(), ...params }
  if (config.quietHoursStart < 0 || config.quietHoursStart > 23) throw new Error('quietHoursStart must be 0-23')
  if (config.quietHoursEnd < 0 || config.quietHoursEnd > 23) throw new Error('quietHoursEnd must be 0-23')
  if (config.maxPerHour < 1) throw new Error('maxPerHour must be >= 1')
  if (config.maxPerDay < 1) throw new Error('maxPerDay must be >= 1')
  if (config.backoffMultiplier <= 1.0) throw new Error('backoffMultiplier must be > 1.0')
  return config
}

