export function createTriggerInput(raw: TriggerInput): TriggerInput {
  if (raw.currentHour < 0 || raw.currentHour > 23) throw new Error('currentHour must be 0-23')
  if (raw.currentMinute < 0 || raw.currentMinute > 59) throw new Error('currentMinute must be 0-59')
  if (raw.continuousWorkDurationMs < 0) throw new Error('continuousWorkDurationMs must be >= 0')
  return raw
}

